 81	// Create initializes the session directory, writes manifest.json, seeds
 82	// turns.jsonl, and creates attachments/.
 83	func (s *ReviewSessionStore) Create(session ReviewSession) error {
 84		if s == nil {
 85			return errors.New("review session store: nil store")
 86		}
 87		root, err := s.sessionRoot(session.ID)
 88		if err != nil {
 89			return err
 90		}
 91	
 92		s.mu.Lock()
 93		defer s.mu.Unlock()
 94	
 95		if err := os.MkdirAll(filepath.Join(root, reviewAttachmentsDir), 0o755); err != nil {
 96			return fmt.Errorf("review session: mkdir attachments: %w", err)
 97		}
 98		if err := writeJSONFile(filepath.Join(root, reviewManifestName), reviewSessionManifestFrom(session)); err != nil {
 99			return err
100		}
101		if err := os.WriteFile(filepath.Join(root, reviewTurnsName), nil, 0o644); err != nil {
102			return fmt.Errorf("review session: seed turns: %w", err)
103		}
104		return nil
105	}
106	
107	// AppendTurn appends a single transcript entry to turns.jsonl.
108	func (s *ReviewSessionStore) AppendTurn(sessionID string, turn ReviewTurn) error {
109		if s == nil {
110			return errors.New("review session store: nil store")
111		}
112		root, err := s.sessionRoot(sessionID)
113		if err != nil {
114			return err
115		}
116	
117		s.mu.Lock()
118		defer s.mu.Unlock()
119	
120		if err := os.MkdirAll(root, 0o755); err != nil {
121			return fmt.Errorf("review session: mkdir session: %w", err)
122		}
123		if turn.CreatedAt.IsZero() {
124			turn.CreatedAt = time.Now().UTC()
125		}
126		path := filepath.Join(root, reviewTurnsName)
127		f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644)
128		if err != nil {
129			return fmt.Errorf("review session: open turns: %w", err)
130		}
131		defer f.Close()
132		if err := json.NewEncoder(f).Encode(turn); err != nil {
133			return fmt.Errorf("review session: encode turn: %w", err)
134		}
135		return nil
136	}
