229	func writeJSONFile(path string, v any) error {
230		data, err := json.MarshalIndent(v, "", "  ")
231		if err != nil {
232			return fmt.Errorf("review session: marshal %s: %w", path, err)
233		}
234		data = append(data, '\n')
235		if err := os.WriteFile(path, data, 0o644); err != nil {
236			return fmt.Errorf("review session: write %s: %w", path, err)
237		}
238		return nil
239	}

