718			coordinator := m.LandCoordinators.Get(projectRoot)
719	
720			// singleTierAttempt runs one execution at a specific harness/model.
721			// The caller controls MinPower per rung; this helper keeps the
722			// profile stable and only advances the power floor.
723			singleTierAttempt := func(ctx context.Context, beadID string, requestedMinPower int, resolvedHarness, resolvedProvider, resolvedModel string) (agent.ExecuteBeadReport, error) {
724				gitOps := &agent.RealGitOps{}
725				attemptProvider := spec.Provider
726				if resolvedProvider != "" {
